sql:
SELECT COUNT(DISTINCT cert) 
FROM bank_electronic_reporting 
WHERE edepfor > 0;

external_knowledge:
- "seeds of trust" refers to bank certification numbers;
- "sprouted" refers to the presence of a bank certification number in the database;
- "watchful eye of the Federal Reserve" refers to the regulatory agent being the Federal Reserve;
- "fertile ground of FDIC supervision" refers to the FDIC supervisor number being 'FDIC Supervision';
- "more than 10 sprouts in each plot" refers to the condition of having more than 10 bank certifications in each group.

sql:
SELECT cert
FROM bank_local_details
WHERE local_employee_count = (SELECT MAX(local_employee_count) FROM bank_local_details);

external_knowledge:
- 'Active FDIC status' indicates that the bank is currently insured by the FDIC.;
- 'More than 10 branches' refers to the number of local branches the bank operates.;
- 'Active holding company' means the holding company is currently operational and not in a dissolved or inactive state.;
- 'Banking Code' is a specific regulatory code that describes the bank's compliance and operational standards.;
- 'Most recent ownership and classification details' means the latest entries in the ownership and classification records for each bank.

sql:
SELECT ownership_percentage 
FROM bank_ownerships 
WHERE ownership_percentage > '50%';

SELECT bkclass, classification_description
FROM bank_classifications
WHERE cert = 12345;

SELECT cert, fdic_insurance_limit
FROM bank_FDIC_details
WHERE fdic_status = 'Active';

SELECT agent_name, agent_contact 
FROM bank_regulatory_agents 
WHERE agent_phone LIKE '%1234567890%';

SELECT COUNT(DISTINCT cert) AS count_of_bank_certifications_with_majority_owners
FROM bank_ownerships
WHERE ownership_percentage = '50%';

SELECT DISTINCT T1.owner_name, T1.cert 
FROM bank_ownerships T1 
WHERE CAST(REPLACE(REPLACE(T1.ownership_percentage, '%', ''), ',', '') AS REAL) > 50;

external_knowledge:
- 'Majority ownership' typically means owning more than 50% of the shares or assets;
- 'Active FDIC status' indicates that the bank is currently insured by the Federal Deposit Insurance Corporation;
- 'Parent holding company' refers to a company that owns a controlling interest in one or more subsidiaries.

sql:
SELECT COUNT(cert) 
FROM bank_FDIC_details 
WHERE fdic_status = 'Active';

SELECT DISTINCT owner_name
FROM bank_ownerships
ORDER BY owner_name ASC;

SELECT agent_name, agent_phone
FROM bank_regulatory_agents
ORDER BY agent_name ASC;

SELECT bkclass, classification_description
FROM bank_classifications
ORDER BY bkclass ASC;

external_knowledge:
- "Significant financial metrics" include total assets greater than $1,000,000 and a maximum electronic deposit exposure greater than $500,000;
- "Substantial number of local branches" means more than 5 local branches;
- "Latest reporting date" refers to the most recent financial reporting date, which should be after January 1, 2020.

- "Mostly compliant" means the number of compliant reports exceeds the number of non-compliant reports;
- "Significant assets" refers to total assets exceeding $100,000,000;
- "Local branches" are the operational units of the bank within a specific region.

- 'National Bank' is a specific type of bank classification;
- The classification start date indicates when the bank was officially classified as a 'National Bank';
- 'Local assets' refer to the total assets of a bank's local operations.

sql:
SELECT city, local_employee_count
FROM bank_local_details
ORDER BY local_employee_count DESC;

SELECT cert
FROM bank_reporting_dates
WHERE insdate IS NULL;

external_knowledge:
- 'Trust company flag' set to 1 indicates the owner is a trust company;
- 'Ownership start date' is the date when the ownership began;
- 'FDIC insurance limit' is the insurance coverage provided by the Federal Deposit Insurance Corporation for the bank;
- 'Average insurance limit' is the mean insurance coverage for the group of owners.

sql:
SELECT owner_name, ownership_percentage, ownership_start_date
FROM bank_ownerships
ORDER BY ownership_start_date DESC;
